from collections.abc import Callable

from dependency_plan import dependency_plan


class Container:
    def __init__(self) -> None:
        self._providers: dict[str, Callable[..., object]] = {}

    def register(self, name: str, factory: Callable[..., object]) -> None:
        self._providers[name] = factory

    def resolve(self, name: str) -> object:
        try:
            factory = self._providers[name]
        except KeyError:
            raise KeyError(f"no provider registered for {name!r}") from None

        dependencies = [
            self.resolve(item.name) for item in dependency_plan(factory)
        ]
        return factory(*dependencies)

