from dependency_plan import Dependency, dependency_plan
from service_container import Container


def test_plan_includes_required_positional_and_skips_default():
    def make_report(database, formatter="plain"):
        return database, formatter

    assert dependency_plan(make_report) == (
        Dependency("database", "positional"),
    )


def test_container_resolves_positional_dependency_chain():
    container = Container()
    container.register("settings", lambda: {"dsn": "memory"})

    def database(settings):
        return f"db:{settings['dsn']}"

    def application(database):
        return f"app:{database}"

    container.register("database", database)
    container.register("application", application)

    assert container.resolve("application") == "app:db:memory"
